from assertpy import assert_that
from docopt import DocoptExit
from hypothesis import given
from hypothesis import strategies as st
from my.error import CommandNotFound, Error
from my.scripting import (
    STATUS,
    ErrorManager,
    check_available,
    docopt,
    exit_error,
    handle_error,
)
from pytest import raises


def describe_function_docopt():
    """la fonction docopt()"""

    def it_wraps_docopt(mocker):
        """emballe la fonction docopt()"""
        mock = mocker.patch("my.scripting._docopt")

        docopt("foo")

        mock.assert_called_once_with("foo")

    def it_handles_exception(mocker, capsys):
        """gère les exceptions DocoptExit"""
        mocker.patch(
            "my.scripting._docopt",
            side_effect=DocoptExit("foo"),
        )

        with raises(SystemExit) as e:
            docopt()

        captured = capsys.readouterr()
        assert captured.err == "foo\n"

        assert e.value.code == STATUS.USAGE


def describe_function_check_available():
    """la fonction check_available()"""

    def it_wraps_check_available(mocker):
        """emballe la fonction check_available()"""
        mock = mocker.patch("my.scripting._check_available")

        check_available("foo")

        mock.assert_called_once_with("foo")

    def it_handles_exception(mocker, capsys):
        """gère les exceptions CommandNotFound"""
        mocker.patch(
            "my.scripting._check_available",
            side_effect=CommandNotFound("foo"),
        )

        with raises(SystemExit) as e:
            check_available()

        captured = capsys.readouterr()
        assert captured.err == f"erreur: {CommandNotFound.message}: foo.\n"

        assert e.value.code == STATUS.NOT_FOUND


def describe_function_exit_error():
    """la fonction exit_error()"""

    def it_needs_a_message():
        """nécessite qu'un message soit spécifié"""
        assert_that(exit_error).raises(TypeError).when_called_with()

    def it_prints_error_message(stderr):
        """affiche le message spécifié sur la sortie d'erreur"""
        with raises(SystemExit):
            exit_error("foo")

        assert_that(stderr()).is_equal_to("erreur: foo.")

    @given(status=st.integers(min_value=STATUS.MIN, max_value=STATUS.MAX))
    def it_exits_with_given_status(status: int):
        """termine le script avec le code de status spécifié"""

        with raises(SystemExit) as e:
            exit_error("foo", status)

        assert_that(e.value.code).is_equal_to(status)


def describe_function_handle_error():
    """la fonction handle_error()"""

    @given(message=st.text())
    def it_prints_error_message_from_exception(stderr, message: str):
        """affiche le message de l'exception sur la sortie d'erreur"""
        e = Error()
        e.message = message

        with raises(SystemExit):
            handle_error(e)

        assert_that(stderr()).is_equal_to(f"erreur: {message}.")

    @given(status=st.integers(min_value=STATUS.MIN, max_value=STATUS.MAX))
    def it_exits_with_status_from_exception(status: int):
        """termine le script avec le code de status de l'exception"""
        e = Error()
        e.status = status

        # TODO Le code de retour des exceptions devrait pouvoir être testé via
        # assertpy. Mais la fonction `when_called_with()` chaîne sur la
        # représentation textuelle de l'exception levée. Il faudrait
        # implémenter un système similaire à celui utilisé pour les commandes
        # shell, qui permet de chaîner sur une sujet différent avec les
        # fonctions `and_*`.
        with raises(SystemExit) as ex:
            handle_error(e)

        assert_that(ex.value.code).is_equal_to(status)


def describe_class_ErrorManager():
    """la classe ErrorManager"""

    def it_prevents_error_with_success_code():
        """il empêche les erreurs avec un code de succès"""
        em = ErrorManager()

        (
            assert_that(em.error)
            .raises(ValueError)
            .when_called_with("foo", STATUS.SUCCESS)
        )

    @given(
        messages=st.lists(
            elements=st.text(
                alphabet=st.characters(codec="utf-8", exclude_characters="\n")
            ),
            min_size=1,
        )
    )
    def it_shows_specified_messages_on_stderr(stderr, messages: list[str]):
        """affiche les messages spécifiés sur la sortie d'erreur"""
        em = ErrorManager()
        expected = []

        for message in messages:
            em.error(message, STATUS.FAILURE)
            expected.append(f"erreur: {message}.")

        assert_that(stderr()).is_equal_to_lines(*expected)

    @given(
        code=st.integers(min_value=STATUS.FAILURE, max_value=STATUS.MAX),
        error_count=st.integers(min_value=1, max_value=50),
    )
    def it_exits_with_specified_status_code(code: int, error_count: int):
        """quitte avec le code statut spécifié"""
        em = ErrorManager()

        for i in range(1, error_count + 1):
            em.error("foo", code)

        with raises(SystemExit) as e:
            em.exit()

        assert_that(e.value.code).is_equal_to(code)

    @given(
        codes=st.lists(
            elements=st.integers(
                min_value=2,
                max_value=STATUS.MAX,
            ),
            min_size=2,
            unique=True,
        )
    )
    def it_exits_with_generic_failure_code(codes: list[int]):
        """quitte avec un code status générique lorsque plusieurs erreurs avec
        des codes différents ont été émises"""
        em = ErrorManager()

        for code in codes:
            em.error("foo", code)

        with raises(SystemExit) as e:
            em.exit()

        assert_that(e.value.code).is_equal_to(STATUS.FAILURE)
